                    </div>
                    <ul class="nav nav-pills flex-column left-tab mt-2 responivecustomtab" id="myTab" role="tablist">
              <li class="nav-item">
                <a class="nav-link left-menu" :class="{ 'active': activeKey == 1 }" data-bs-target="#tab-lead-content"
