              </li>
            
            </ul>
                </div>
                <div class="right-content">
                    <div class="col-md-12 p-0 mb-2">
                        <div class="theme-primary partition p-actions-expand">
                            <span class="p-name text-white" id="span_ForSelectedTabName"></span>
                            <span class="p-actions float-right">
                                <RouterLink to="/CRM/ContactListing"  class="p-action-btn text-white float-right">
                                    <em class="fa fa-angle-double-left"></em>
                                    <br />
                                    {{ $t('BacktoList') }}
