                                <a href="javascript:;" v-bind:class="{ 'p-action-btn text-white': true, 'disabled': false }" title
                    data-toggle-tooltip="tooltip" data-original-title="Card View" v-on:click="NoteListType = 'card'"
                    v-if="isNotes && NoteListType == 'list'">
                    <em class="fa fa-th-large"></em>
                    <br />
                    {{ $t('CardView') }}
                  </a>
                  <a href="javascript:;" v-bind:class="{ 'p-action-btn text-white': true, 'disabled': false }" title
                    data-toggle-tooltip="tooltip" data-original-title="List View" v-on:click="NoteListType = 'list'"
                    v-if="isNotes && NoteListType != 'list'">
                    <em class="fa fa-list"></em>
                    <br />
                    {{ $t('ListView') }}
                  </a>
                  <a href="javascript:;" v-bind:class="{ 'p-action-btn text-white': true, 'disabled': false }" title
                    id="ancaddnotesloaddata" data-toggle-tooltip="tooltip" data-original-title="Add Notes"
                    v-on:click="openShowNotePopup()" v-if="isNotes">
                    <em class="fa fa-plus"></em>
                    <br />
                    {{ $t('AddNotes') }}
                  </a>
                  <a href="javascript:;"
                  v-bind:class="{'p-action-btn text-white':true}"
                    :title="$t('UploadFile')" v-if="isAttachment" v-on:click="openCRMAttachmentModal(null);">
                    <em class="fa fa-plus"></em>
                    <br />
                    {{ $t('Add') }} {{ $t('Attachment') }}
                  </a>
                                <a href="javascript:void(0)" v-bind:class="{'p-action-btn text-white btn_add':true}"
                                    title="" id="" v-on:click="openAddTaskModel()" data-original-title="Add Task"
                                    v-if="isTask"><em class="fa fa-plus"></em><br />{{ $t('AddTask') }}</a>
                                <a href="javascript:void(0)" v-bind:class="{'p-action-btn text-white btn_follow':true}"
                                    title="" id="" v-on:click="openAddNewEvent()" data-original-title="Follow Up"
                                    v-if="isTimeline"><em class="fa fa-share"></em><br /> {{ $t('FollowUp') }}</a>
                                    <a href="javascript:void(0)" v-bind:class="{ 'p-action-btn text-white btn_call': true }" title id
                    v-on:click="openCallEvent()" v-if="isTimeline" data-original-title="Schedule Call">
                    <em class="fa fa-phone"></em>
                    <br />
                    {{ $t('Schedule') }} {{ $t('Call') }}
                  </a>
                  <RouterLink :to="editUrl"
                  v-if="isEdit"
                    class="p-action-btn text-white">
                    <em class="fa fa-pencil"></em><br />{{ $t('Edit') }} {{ $t('Contact') }}
                  </RouterLink>
                            </span>
                            <span class="collapse-head-btns">
                                <a href="javascript:;" class="collapse-btns"><em class="fa fa-angle-up text-white"></em></a>
                            </span>
                        </div>
                    </div>
                    <div class="col-md-12 p-0">
                        <div class="tab-content fsmtabcontrolMobileView" id="myTabContent">
                            <div class="expand-list">
                                <a href="javascript:;"
                                    class="expand-list-btn justify-content-center align-items-center">
                                    <em class="icon-solid arrow-solid-left text-white" style="font-size:9pt"></em>
                                </a>
                            </div>
                            <div class="tab-pane p-0 pb-2 border-0" role="tabpanel" id="tab-contact-content"
                                aria-labelledby="tab-contact-content" :class="{ 'active show': activeKey == 1 }"> 
                                <div class="listing">
                                    <div class="row">
                                        <div class="col-md-12">
                                            <div class="card mb-3 probx">
                                                <div class="card-header">
                                                    <h2>{{$t("Details")}}</h2>
                                                    <div class="cont_right ">
                                                        <div class="bar">
                                                        </div>
                                                    </div>
                                                </div>
                                                <div class="card-body">
                                                    <div class="panel1" v-for="group in LeftViewData">
                                                        <div class="heading-border">
                                                            <h5 class="h5 mb-2">
                                                                <span>{{$t(group.group_display_name,group.group_name)}}</span>
                                                            </h5>
                                                        </div>
                                                        <div class="row">
                                                            <div class="col-md-6 col-lg-3"
                                                                v-for="(item, index) in group.LeftViewData" :key="index">
                                                                <div class="form-group">
                                                                    <label>
                                                                        <strong>{{$t(item.display_name, item.name)}}:</strong>
                                                                        <span class="answer rightlabeltext ml-1"
                                                                            v-if="item.dt_code == 'date' || item.dt_code == 'datetime'">
                                                                            {{item.value | formatDate}}</span>
                                                                        <span class="answer rightlabeltext ml-1"
                                                                            v-if="item.dt_code == 'decimal'">{{isBlank(item.value)?"0.00":item.value | currency}}</span>
                                                                        <span class="answer rightlabeltext ml-1"
                                                                            v-if="item.dt_code != 'date' && item.dt_code != 'datetime'  && item.dt_code != 'decimal' && 
                                                                            item.picklist_options != 'Lookup'">{{
                                                                            isBlank(item.value)?"--":(item.value)}}</span>
                                                                        <span class="answer rightlabeltext ml-1"
                                                                            v-if="item.dt_code != 'date' && item.dt_code != 'datetime'  && item.dt_code != 'decimal' && 
                                                                            item.picklist_options == 'Lookup'">{{
                                                                            isBlank(item.value)?"--":(item.value)}}</span>
                                                                    </label>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                            <div class="card mb-3 probx">
                                                <div class="card-header">
                                                    <h2>{{$t("Timeline")}}</h2>
                                                </div>
                                                <div class="card-body">
                                                   
                                                    <crmtimeline v-bind:timelinedata="timelinedata"></crmtimeline>
                                                </div>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>

                            <div class="tab-pane fade p-0 pb-2 border-0" role="tabpanel" id="tab-notes-content"
                                aria-labelledby="tab-notes-content" :class="{ 'active show': activeKey == 2 }">
                                <crmnote v-if="noteData" v-bind:notedata="noteData" :userid="userid" :companyid="companyId"
                    :sourceid="$route.params.id" :modulename="$route.params.moduleName"
                    :submodulecode="$route.params.subModuleCode" v-bind:listtype="NoteListType"
                    :showNotePopUp="isShowNotePopup" callfrom="quickViewAndNoteJS"></crmnote>                              

                    
                            </div>
                            <div class="tab-pane fade p-0 pb-2 border-0" role="tabpanel" id="tab-attachment-content"
                                aria-labelledby="tab-attachment-content" :class="{ 'active show': activeKey == 3 }">
                                
                                    <crmattachment v-bind:attachmentdata="attachmentData" :sourceid="$route.params.id"></crmattachment>
                            </div>
                            <div class="tab-pane fade p-0 border-0 listing" role="tabpanel"
                                id="tab-openactivities-content" aria-labelledby="tab-openactivities-content" :class="{ 'active show': activeKey == 4 }">
                                <input id="hdnshowspliticon" value="1" type="hidden">
                                <div class="table-responsive tableborder customborder_lightgrey float-left crm_rightpanelmaximumscroll_table_btns"
                                    v-if="!noRecordForTab">
                                    <table class="table table-bordered mb-0" id="table-openactivities-content" aria-describedby="activitescontent">
                                        <thead class="thead-bg">
                                            <tr>
                                                 <th scope="col">
                            <span>{{ $t('Subject') }}</span>
                          </th>
                           <th scope="col">
                            <span>{{ $t('Activity') }} {{ $t('Type') }}</span>
                          </th>
                           <th scope="col">
                            <span>{{ $t('Activity') }} {{ $t('ScheduleDate') }}</span>
                          </th>
                           <th scope="col">
                            <span>{{ $t('Activity') }} {{ $t('OWNER') }}</span>
                          </th>
                           <th scope="col">
                            <span>{{ $t('CreatedAt') }}</span>
                          </th>
                           <th scope="col">
                            <span>{{ $t('Status') }}</span>
                          </th>
                           <th scope="col" class="text-center">
                            <span>{{ $t('Action') }}</span>
                          </th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            <tr v-for="(item,index) in activitiesData" :key="index">
                                                <td><a href="javascript:;"
                                                        v-on:click="openActivityModal(item);">{{item.followup_notification_subject}}</a>
                                                </td>
                                                <td>
                                                    <div v-if="item.activity_type === 'FollowUp'">
                                                        Follow up
                                                    </div>
                                                    <div v-else>
                                                        {{item.activity_type}}
                                                    </div>
                                                </td>
                                                <td>{{item.followup_notification_schedule | formatDate}}</td>
                                                <td>{{item.activity_owner}}</td>
                                                <td>{{item.created_at | formatDate}}</td>
                                                <td><span
                                                        v-bind:class="{'px-2 bg-success text-white d-block text-center': (item.status_name == 'Active'),'px-2 bg-danger text-white d-block text-center': (item.status_name == 'Inactive')}">{{item.status_name}}</span>
                                                </td>
                                                <td class="single-action text-center"><a href="javascript:;"
                                                        title="Delete" v-on:click="DeleteActivity(item);"><em                        class="fa fa-trash action-icon text-danger"></em></a></td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                                <div v-if="noRecordForTab" class="text-center text-danger p-4 border no-record">
                                   {{ $t("NoRecordfound")}}</div>
                            </div>
                        </div>
                    </div>
                </div>
            
    </section>
    <modaltask v-if="showAddTaskModal" @close="showAddTaskModal = false, modalTaskItem = null"
      :modalTaskItem="modalTaskItem">
      <h5 slot="header" class="modal-title">{{ $t('AddTask') }}</h5>
    </modaltask>
    <modalattachment v-if="showAttachmentModal" @close="showAttachmentModal = false" :userid="userid"
      :companyid="companyId" :id="$route.params.id" :modulename="$route.params.moduleName"
      :submodulecode="$route.params.subModuleCode" :containername="containername" imagesizedata="">
      <h5 slot="header" class="modal-title">$t('Attachments')</h5>
    </modalattachment>
    <modalevent v-if="showAddEventModal" @close="showAddEventModal = false, modalFollowUpItem = null"
      :modalFollowUpItem="modalFollowUpItem" v-bind:modulename="$route.params.moduleName"
      v-bind:submodulecode="$route.params.subModuleCode" :sourceid="$route.params.id">
      <h5 slot="header" class="modal-title">{{ $t('FollowUp') }}</h5>
    </modalevent>
    <modalcall v-if="showCallModal" :modalCallItem="modalCallItem" @close="showCallModal = false, modalCallItem = null">
      <h5 slot="header" class="modal-title">{{ $t('Schedule') }} {{ $t('Call') }}</h5>
    </modalcall>
</div>
</template>
<script>
import LeadDataService from "../../../services/DataService";
import crmtimeline from "../../../components/Common/Modal/crmtimeline.vue";
import crmnote from "../../../components/Common/Modal/crmnote.vue";
import crmattachment from "../../../components/Common/Modal/crmattachment.vue";
import modaltask from "../../../components/Common/Modal/modaltask.vue";
import modalattachment from "../../../components/Common/Modal/modalattachment.vue";
import modalevent from "../../../components/Common/Modal/modalevent.vue";
import modalcall from "../../../components/Common/Modal/modalcall.vue";
import $ from "jquery";
export default {
    components: {
    crmtimeline,
    crmnote,
    crmattachment,
    modaltask,
    modalattachment,
    modalevent,
    modalcall
    },
  data() {
    return {
        activeKey: 1,
        isTimeline: false,
        isNotes: false,
        isAttachment: false,
        isSendEmail: false,
        isTask: false,
        isEdit: true,
        LeftViewData: [],
        isShowNoteDialogue: null,
        RightViewData: null,
        showAddTaskModal: false,
        showAddEventModal: false,
        showCallModal: false,
        attachmentData: [],
        activitiesData: null,
        timelinedata: [],
        noteData: [],
        productData: null,
        productHeaders: null,
        noRecordForTab: false,
        showAttachmentModal: false,
        modalItem: null,
        modalTaskItem: null,
        modalFollowUpItem: null,
        modalCallItem: null,
        modalDeleteItem: null,
        contactName: '--',
        noteText: '',
        SortBy: '',
        SortExp: '',
        PageNumber: 1,
        PageSize: 50,
       isView: false,
        modal: null,
        isShowNotePopup: false,
        userid: null,
        companyId: null,
        containername: null,
        email: null,
        NoteListType: 'list',
        editUrl: `/CRM/ManageContact/${this.$route.params.id}/${this.$route.params.moduleName}/${this.$route.params.subModuleCode}`, 
        ApiURL: `id=${this.$route.params.id}&refId=${this.$route.params.id}&moduleName=${this.$route.params.moduleName}&subModuleCode=${this.$route.params.subModuleCode}`,
        isLoading:false,
   
  };
},
    
    created: function () {
   
        this.userid= this.GetUserInfo.ID;
        this.companyId= this.GetUserInfo.CompanyId;
        this.containername= this.GetUserInfo.ContainerName;
        this.email= this.GetUserInfo.Email;
        this.FetchData();
    },
    updated(){ 
        var vm=this; 
        setTimeout(function () { vm.setHeaderForSelectedTab() }, 500);
    },
    methods: {
        DisableButton: function () {
           var vm = this;
            vm.isTimeline = false;
            vm.isNotes = false;
            vm.isAttachment = false;
            vm.isSendEmail = false;
            vm.isTask = false;
            vm.isEdit = true;
        },
       
        formatDate: function (value) {
            if (value) {
                return moment(value, String(Globalize.culture().calendar.patterns.d).toUpperCase()).format(String(Globalize.culture().calendar.patterns.d).toUpperCase())
            }
        },
        openNoteDialogue() {
            this.isShowNoteDialogue = (this.isShowNoteDialogue) ? false : true;
        },
        openAddTaskModel() {
            this.showAddTaskModal = (this.showAddTaskModal) ? false : true;
        },
        openAddNewEvent() {
            this.showAddEventModal = (this.showAddEventModal) ? false : true;
        },
        openCallEvent() {
            this.showCallModal = (this.showCallModal) ? false : true;
        },
        DeleteActivityData: function (id) {
            var vm = this;
            if (id > 0) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, null, function () {
                   
                        var postJSON = {
                            ids: id,
                            moduleName: "CRM",
                            subModuleCode: vm.$route.params.subModuleCode,
                            refCode: 'DELETE_VIEW_ACTIVITY',
                            refId: vm.$route.params.id
                            };
                        var objectPostString = JSON.stringify(postJSON);
                      
                        LeadDataService.CommonDelete(objectPostString).then(function (response) {
                            if (response.data[0].Status == "Success") {
                                vm.ShowAlert(vm.$t("DeletedSuccess",[vm.$t("Activity")]),'success',true,vm.$t('Alert'));
                                vm.loadData('activities');
                            }
                            else {
                                vm.ShowAlert(vm.$t("DeletedError",[vm.$t("Activity")]),'failure',true,vm.$t('Alert'));
                            }
                             
                        }, response => {
                             
                        });
                   
                });
            }
        },
        FetchData: function () {
            var vm = this;
            vm.isLoading=true;
            LeadDataService.FormLayoutView(vm.ApiURL).then(function (response) {
                if(response.data !=''){
                    var fullLeftJSON = response.data.LEFTDATA;
                    fullLeftJSON = $.grep(fullLeftJSON, function (element, index) {
                        return element.form_field_visibility == 'YES';
                    });
                    //right data object returns the data for timeline
                    if (response.data.RIGHTDATA != null && response.data.RIGHTDATA.length > 0) {
                    var fullJSON = response.data.RIGHTDATA;
                    var gruopBy = "";
                    fullJSON.forEach(item => {
                        gruopBy = vm.$options.filters.formatDate(item.Complete_datetime);
                        var chkGroup = $.grep(vm.timelinedata, function (element, index) {
                            return element.groupKey == gruopBy;
                        });
                        if (chkGroup.length == 0) {
                            var returnedData = $.grep(fullJSON, function (element, index) {
                            return vm.$options.filters.formatDate(element.Complete_datetime) == gruopBy;
                            });
                            if (returnedData.length > 0) {
                            var objGroup = {
                                groupKey: gruopBy,
                                groupData: returnedData,
                            };
                            vm.timelinedata.push(objGroup);
                            }
                        }
                    });
                    vm.isLoading=false;
                        vm.noRecordForTab = false;
                    } else {
                        vm.noRecordForTab = true;
                    }
                    if (fullLeftJSON != null && fullLeftJSON.length > 0) {
                        var groupId = fullLeftJSON[0].group_id;
                        $.each(fullLeftJSON, $.proxy(function (index, item) {
                            if (item.name == 'first_name') {
                                this.contactName = item.value;
                            }
                            if (item.name == 'last_name') {
                                this.contactName = vm.contactName + ' ' + item.value;
                            }
                            if (item.name == "email_id") {
                            { { item.value = vm.$options.filters.truncate(item.value, 24, '...') } }
                            }
                            var chkGroup = $.grep(vm.LeftViewData, function (element, index) {
                                return element.group_id == groupId;
                            });
                            if (chkGroup.length == 0) {
                                var returnedData = $.grep(fullLeftJSON, function (element, index) {
                                    return element.group_id == groupId;
                                });
                                if (returnedData.length > 0) {
                                    var objGroup = {
                                        group_id: groupId,
                                        group_name: returnedData[0].group_name,
                                        group_display_name: returnedData[0].group_display_name ? returnedData[0].group_display_name : returnedData[0].group_name,
                                        LeftViewData: returnedData
                                    };
                                    vm.LeftViewData.push(objGroup);
                                }
                            }
                            groupId = item.group_id;
                        }, vm));
                        vm.isLoading=false;
                    }
                }
                    vm.isLoading=false;                    
                })
        },
        openShowNotePopup: function () {
      var ths = this;
      if (
        typeof ths.checkForAdditionalPermission !== "undefined" &&
        !ths.checkForAdditionalPermission("AddNote")
      ) {
        ShowAlert(
          this.$t("additionalOwnerAuthorityWarning",
          [this.$t("warning")]),
          true,
          this.$t("Alert")
        );
      } else {
        ths.isShowNotePopup = true;
        $("#tab-notes").trigger("click");
         ths.loadData("notes");
      }
    },
    checkForAdditionalPermission: function (TypeCode) {
      var rtrn = true;
      if (
        this.additionalOwnerPermission != null &&
        this.additionalOwnerPermission.length > 0
      ) {
        var prmsn = this.additionalOwnerPermission.filter(function (c) {
          return c.permission_code == TypeCode;
        });
        if (prmsn.length == 0) {
          rtrn = false;
        }
      }
      return rtrn;
    },
        changeDateForAddNoteUsrEnd: function (value) {
            try {
                var timeFormat = Globalize.culture().calendar.patterns.t;
                timeFormat = String(timeFormat).replace("t", "A").replace("t", "");
                var getDate = new Date(moment(String(value)).year(), moment(String(value)).month(), moment(String(value)).date(), moment(String(value)).hours(), moment(String(value)).minutes());
                if (userTimeZone[0].indexOf('+') >= 0) {
                    getDate = new Date(getDate.setHours(getDate.getHours() - parseInt(userTimeZone[0].replace("+", ""))));
                    getDate = new Date(getDate.setMinutes(getDate.getMinutes() - parseInt(userTimeZone[1])));
                } else if (userTimeZone[0].indexOf('-') >= 0) {
                    getDate = new Date(getDate.setHours(getDate.getHours() + parseInt(userTimeZone[0].replace("-", ""))));
                    getDate = new Date(getDate.setMinutes(getDate.getMinutes() + parseInt(userTimeZone[1])));
                }
                return moment(getDate, "YYYY-MM-DD HH:mm").format(String(Globalize.culture().calendar.patterns.d).toUpperCase() + " " + String(timeFormat));
            } catch (e) {
                var timeFormat = Globalize.culture().calendar.patterns.t;
                timeFormat = String(timeFormat).replace("t", "a").replace("t", "");
                return moment(String(value)).format(String(Globalize.culture().calendar.patterns.d).toUpperCase() + " " + String(timeFormat));
            }
        },
        openActivityModal(item) {
            if (item.activity_type == "Task") {
                this.showAddTaskModal = true;
                this.modalTaskItem = item;
            }
            else if (item.activity_type == "FollowUp") {
                this.showAddEventModal = true;
                this.modalFollowUpItem = item;
            }
            else if (item.activity_type == "Call") {
                this.showCallModal = true;
                this.modalCallItem = item;
            }
        },
        DeleteActivity(item) {
            this.modalDeleteItem = item;
            this.DeleteActivityData(this.modalDeleteItem.followup_notification_id);
        },
        openCRMAttachmentModal: function () {
if ((typeof this.checkForAdditionalPermission !== 'undefined') && !this.checkForAdditionalPermission("AddAttachment")) {
  alertR(Globalize.localize("additionalOwnerAuthorityWarning"), true, Globalize.localize('Alert'));
} else {

  this.showAttachmentModal = (this.showAttachmentModal) ? false : true;
}
},
       
        loadData(tabName,callFrom) {
            var vm = this;
            vm.DisableButton();
            if (tabName == "notes") {
                vm.isNotes = true;
                vm.isEdit = false;
                if(callFrom && callFrom=='savenote')                
                vm.isShowNotePopup = false;
                vm.activeKey = 2;
            }
            else if (tabName == "attachments") {
                vm.isAttachment = true;
                vm.isEdit = false;
                vm.activeKey = 3;
            }
            else if (tabName == "activities") {
                vm.isTask = true;
                vm.isEdit = false;
                vm.isTimeline = true;
                vm.activeKey = 4;
            }
            if (tabName != "" && tabName != null) {
                 
               
                if (tabName == "attachments") {
                  
                    LeadDataService.AttachmentListing(vm.ApiURL).then(function (response) {
                         
                        if (response.data != null) {
                            vm.attachmentData = response.data.data;                            
                            vm.noRecordForTab = false;
                        } else {
                            vm.noRecordForTab = true;
                        }
                    });
                }
                else if (tabName == "timeline") {
                  
                    LeadDataService.TimelineListing(vm.ApiURL).then(function (response) {
                         
                        if (response.data != null && response.data != "") {
                            vm.timelinedata = [];
                            var fullJSON = response.data.data;
                            var gruopBy = "";
                            $.each(fullJSON, $.proxy(function (index, item) {
                                gruopBy = vm.$options.filters.formatDate(item.Complete_datetime);
                                var chkGroup = $.grep(vm.timelinedata, function (element, index) {
                                    return element.groupKey == gruopBy;
                                });
                                if (chkGroup.length == 0) {
                                    var returnedData = $.grep(fullJSON, function (element, index) {
                                        return vm.$options.filters.formatDate(element.Complete_datetime) == gruopBy;
                                    });
                                    if (returnedData.length > 0) {
                                        var objGroup = {
                                            groupKey: gruopBy,
                                            groupData: returnedData
                                        };
                                        vm.timelinedata.push(objGroup);
                                    }
                                }
                            }, vm));                           
                            vm.noRecordForTab = false;
                        } else {
                            vm.noRecordForTab = true;                            
                        }
                    });
                    vm.activeKey = 1;
                }
                else if (tabName == "notes") {
                    vm.noteData = [];
                  
                    LeadDataService.NoteListing(vm.ApiURL).then(function (response) {
                        if (response.data != null && response.data.data.length > 0) {
                            vm.noteData = response.data.data; 
                            vm.noRecordForTab = false;
                        } else {
                            vm.noRecordForTab = true;
                        }
                    });
                }
                else if (tabName == "activities") {
                   
                    LeadDataService.ActivityListing(vm.ApiURL).then(function (response) {
                         
                        if (response.data != null && response.data.data.length > 0) {
                            vm.activitiesData = response.data.data; 
                            vm.noRecordForTab = false;
                        } else {
                            vm.noRecordForTab = true;
                        }
                    });
                }
            }
        }
    } 
}
</script>